const allItems = $input.all();
const extractItem = allItems[0]?.json || {};
const td = extractItem.data || extractItem;

const analysisItem = allItems[1]?.json || {};
const gradeAnalysis = analysisItem.answer || analysisItem.markdown || analysisItem.text || '';

const triggerData = $('New Transcript').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

// GPA conversion to 4.0 scale
const originalGPA = parseFloat(td.originalGPA) || 0;
const gpaScale    = (td.gpaSCale || td.gpaScale || '4.0').toString();
let convertedGPA  = originalGPA;

if (gpaScale.includes('10') && !gpaScale.includes('100')) {
  // 10-point scale (e.g. Germany, Netherlands)
  convertedGPA = parseFloat((originalGPA / 10 * 4).toFixed(2));
} else if (gpaScale.includes('100') || originalGPA > 10) {
  // Percentage scale (UK, Australia, India etc.)
  // UK classification: 70+=4.0, 60-69=3.3, 50-59=2.7, 40-49=2.0, <40=0
  if      (originalGPA >= 70) convertedGPA = 4.0;
  else if (originalGPA >= 60) convertedGPA = parseFloat((3.3 + (originalGPA - 60) / 10 * 0.4).toFixed(2));
  else if (originalGPA >= 50) convertedGPA = parseFloat((2.7 + (originalGPA - 50) / 10 * 0.6).toFixed(2));
  else if (originalGPA >= 40) convertedGPA = parseFloat((2.0 + (originalGPA - 40) / 10 * 0.7).toFixed(2));
  else convertedGPA = parseFloat((originalGPA / 40 * 2.0).toFixed(2));
  convertedGPA = Math.max(0, Math.min(4, convertedGPA));
} else if (gpaScale.includes('5')) {
  // 5-point scale (Russia, some European countries)
  convertedGPA = parseFloat((originalGPA / 5 * 4).toFixed(2));
} else if (gpaScale.includes('7')) {
  // 7-point scale (Denmark, some others)
  convertedGPA = parseFloat((originalGPA / 7 * 4).toFixed(2));
}
// 4.0 scale - no conversion needed

// Parse credential status from AI analysis
const analysisLower = gradeAnalysis.toLowerCase();
let credentialStatus = 'Verified';
if (analysisLower.includes('fraud') || analysisLower.includes('suspicious'))
  credentialStatus = 'Suspicious - Review';
else if (analysisLower.includes('incomplete') || analysisLower.includes('missing'))
  credentialStatus = 'Incomplete';
else if (analysisLower.includes('unaccredited') || analysisLower.includes('not recognized'))
  credentialStatus = 'Unaccredited Institution';

// US equivalent degree
let usEquivalent = td.degreeType || 'N/A';
const deg = (td.degreeType || '').toLowerCase();
if (deg.includes('bachelor') || deg.includes('licence') || deg.includes('licenciatura'))
  usEquivalent = "Bachelor's Degree";
else if (deg.includes('master') || deg.includes('magister') || deg.includes('maestría'))
  usEquivalent = "Master's Degree";
else if (deg.includes('phd') || deg.includes('doctorate') || deg.includes('doktor'))
  usEquivalent = "Doctoral Degree";
else if (deg.includes('associate') || deg.includes('diploma'))
  usEquivalent = 'Associate Degree / Diploma';

return [{ json: {
  studentName:       td.studentName        || 'Unknown',
  studentId:         td.studentId          || 'N/A',
  dateOfBirth:       td.dateOfBirth        || 'N/A',
  countryOfOrigin:   td.countryOfOrigin    || 'N/A',
  institutionName:   td.institutionName    || 'N/A',
  institutionCountry:td.institutionCountry || 'N/A',
  degreeType:        td.degreeType         || 'N/A',
  usEquivalent,
  major:             td.major              || 'N/A',
  minor:             td.minor              || 'N/A',
  enrollmentYear:    td.enrollmentYear     || 'N/A',
  graduationYear:    td.graduationYear     || 'N/A',
  graduationStatus:  td.graduationStatus   || 'N/A',
  originalGPA,
  gpaScale,
  convertedGPA,
  totalCredits:      td.totalCredits       || 0,
  totalCourses:      td.totalCourses       || 0,
  coursesSummary:    td.coursesSummary     || 'N/A',
  honorsAwards:      td.honorsAwards       || 'None',
  languageOfInstruction: td.languageOfInstruction || 'N/A',
  isOfficial:        td.isOfficial   ? 'Yes' : 'No',
  registrarSignature:td.registrarSignature ? 'Yes' : 'No',
  credentialStatus,
  gradeAnalysis,
  fileName,
  fileId,
  processedAt: new Date().toISOString()
}}];

